import{_ as s,y as a,a as l,o as u,a2 as i,D as n,g as e,I as r}from"./chunks/framework.DCcmcJcL.js";const C=JSON.parse('{"title":"Cart Rules","description":"","frontmatter":{},"headers":[],"relativePath":"marketing/cart-rules.md","filePath":"marketing/cart-rules.md","lastUpdated":1781685029000}'),p={name:"marketing/cart-rules.md"};function g(c,t,h,d,m,f){const o=a("ImagePopup");return u(),l("div",null,[t[0]||(t[0]=i('<h1 id="cart-rules" tabindex="-1">Cart Rules <a class="header-anchor" href="#cart-rules" aria-label="Permalink to &quot;Cart Rules&quot;">​</a></h1><p>It is human nature that everyone is attracted to offers, sales, and discounts while shopping. A Cart Rule is applied to the product in the shopping cart. Here we will discuss how to set cart rules in Bagisto.</p><p>By using it, you can set one or multiple discounts on the same product. Follow the below steps to learn <strong>how to set cart rules in Bagisto</strong>.</p><h3 id="step-1-add-new-cart-rule" tabindex="-1">Step 1: Add New Cart Rule <a class="header-anchor" href="#step-1-add-new-cart-rule" aria-label="Permalink to &quot;Step 1: Add New Cart Rule&quot;">​</a></h3><ol><li>In the Admin Panel, go to <strong>Marketing &gt;&gt; Promotions &gt;&gt; Cart Rules</strong>.<br> Click on <strong>Create Cart Rule</strong> as shown in the image below.</li></ol>',5)),n(o,{src:"/images/marketing/createCartrule.png",alt:"Create Cart Rule"}),t[1]||(t[1]=i('<p>From the Cart Rules listing page, you can also <strong>Copy</strong> an existing rule by clicking the Copy icon in the action column. This creates a duplicate with &quot;Inactive&quot; status, allowing you to modify and enable it later.</p><h3 id="rule-information-section" tabindex="-1">Rule Information Section <a class="header-anchor" href="#rule-information-section" aria-label="Permalink to &quot;Rule Information Section&quot;">​</a></h3><ol><li><p><strong>Name:</strong> Enter the name of the new cart rule (only for internal reference).</p></li><li><p><strong>Description:</strong> Enter a description of the rule (only for internal reference).</p></li><li><p><strong>Status:</strong> Toggle the status switch to Active or Inactive.</p></li><li><p><strong>Priority:</strong> Enter the priority of this rule. Lower numbers have higher priority. When multiple rules match, the rule with the lowest sort order is applied first.</p></li></ol><p><strong>Note:</strong> Priority is important when products meet the condition set for more than one cart rule. The highest priority is 0. So when multiple conditions are met, the rule with the highest priority will be applied first.</p><h3 id="settings-right-sidebar" tabindex="-1">Settings (Right Sidebar) <a class="header-anchor" href="#settings-right-sidebar" aria-label="Permalink to &quot;Settings (Right Sidebar)&quot;">​</a></h3><p>The Settings panel is located in the right sidebar and contains:</p>',6)),n(o,{src:"/images/marketing/cart-rule-right.png",alt:"Create Cart Rule Right Sidebar Settings"}),t[2]||(t[2]=i('<ol><li><p><strong>Priority:</strong> Enter the sort order/priority of this rule.</p></li><li><p><strong>Channels:</strong> Select one or more channels by checking the checkboxes. The cart rule will only apply to the selected channels.</p></li><li><p><strong>Customer Groups:</strong> Select one or more customer groups by checking the checkboxes. The cart rule will only apply to the selected customer groups.</p></li><li><p><strong>Status:</strong> Toggle the switch to enable or disable the cart rule.</p></li></ol><h3 id="marketing-time-right-sidebar" tabindex="-1">Marketing Time (Right Sidebar) <a class="header-anchor" href="#marketing-time-right-sidebar" aria-label="Permalink to &quot;Marketing Time (Right Sidebar)&quot;">​</a></h3><p>The Marketing Time panel is located below Settings in the right sidebar:</p><ol><li><p><strong>From:</strong> Set the start date and time from which the cart rule becomes active. Leave blank to apply immediately.</p></li><li><p><strong>To:</strong> Set the end date and time after which the cart rule expires. Leave blank for no expiry.</p></li></ol><h3 id="coupon-section" tabindex="-1">Coupon Section <a class="header-anchor" href="#coupon-section" aria-label="Permalink to &quot;Coupon Section&quot;">​</a></h3><ol><li><strong>Coupon Type:</strong> Select coupon type with or without a coupon. If you want the cart rule to apply to all carts without requiring a coupon code, set it to <strong>No Coupon</strong>. Select <strong>Specific Coupon</strong> to require a coupon code.</li></ol><p><strong>If you select Specific Coupon, configure the following fields:</strong></p>',7)),n(o,{src:"/images/marketing/cart-rule-generate-coupon.png",alt:"Create Cart Rule Coupon"}),t[3]||(t[3]=i("<ol><li><p><strong>Auto Generate Coupon:</strong> Set Yes to have the system generate coupon codes automatically. Set No to enter a coupon code manually.</p></li><li><p><strong>Coupon Code:</strong> If Auto Generate Coupon is set to No, enter the coupon code that customers will use during checkout.</p></li><li><p><strong>Uses Per Coupon:</strong> Define how many times the coupon code can be used in total. Leave blank for unlimited uses.</p></li><li><p><strong>Uses Per Customer:</strong> Define how many times the same customer can use this cart rule. Leave blank for unlimited.</p></li></ol><p><strong>If Auto Generate Coupon is set to Yes, you can generate bulk coupons after saving the rule. On the edit page, a Generated Coupons section appears where you can click Generate Coupons and configure:</strong></p>",2)),n(o,{src:"/images/marketing/cart-rule-generate-now.png",alt:"Cart Rule Coupon Generate"}),t[4]||(t[4]=i("<ul><li><strong>Coupon Quantity:</strong> Number of unique coupon codes to generate.</li><li><strong>Code Length:</strong> Length of each coupon code (minimum 10).</li><li><strong>Code Format:</strong> Format of the generated codes — <strong>Alphanumeric</strong> (A-Z, 0-9), <strong>Alphabetical</strong> (A-Z only), or <strong>Numeric</strong> (0-9 only).</li><li><strong>Code Prefix:</strong> Optional prefix added to every generated coupon code.</li><li><strong>Code Suffix:</strong> Optional suffix added to every generated coupon code.</li></ul><p><strong>How Auto-Generated Coupons Work on the Frontend:</strong></p><p>Each auto-generated coupon code is a unique code that customers can use at checkout. These codes work the same way as a manually entered coupon — the customer enters the code in the <strong>Apply Coupon</strong> field on the checkout page.</p><p>Auto-generated coupons are useful for marketing campaigns where you need to distribute many unique codes (e.g., email campaigns, loyalty programs). Each generated code has its own usage tracking based on the <strong>Uses Per Coupon</strong> and <strong>Uses Per Customer</strong> limits configured in the rule.</p>",4)),n(o,{src:"/images/marketing/configurations.png",alt:"Cart Rule Configurations"}),t[5]||(t[5]=e("p",null,[r("You can also set "),e("strong",null,"No Coupon"),r(" if you want the discount to apply automatically to all eligible carts without requiring any code entry.")],-1)),n(o,{src:"/images/marketing/configurations.png",alt:"Cart Rule Configurations"}),t[6]||(t[6]=i('<h3 id="step-2-set-conditions" tabindex="-1">Step 2: Set Conditions <a class="header-anchor" href="#step-2-set-conditions" aria-label="Permalink to &quot;Step 2: Set Conditions&quot;">​</a></h3><p>Conditions define when the cart rule should be applied. They are based on three categories of attributes:</p><ul><li><strong>Cart Attributes:</strong> Sub Total, Items Qty, Payment Method, Shipping Method, Postcode, State, Country.</li><li><strong>Cart Item Attributes:</strong> Base Price, Quantity, Base Total Weight, Base Total.</li><li><strong>Product Attributes:</strong> Category IDs, Attribute Family, plus all product EAV attributes (excluding textarea, image, and file types).</li></ul><p>If you want to apply the rule to all products without any restriction, leave the conditions section empty.</p><p><strong>Condition Type:</strong></p><ul><li><strong>All Conditions are True:</strong> Every condition must be satisfied for the rule to apply.</li><li><strong>Any Condition is True:</strong> At least one condition must be satisfied for the rule to apply.</li></ul>',6)),n(o,{src:"/images/marketing/condition.png",alt:"Set Cart Rule Conditions"}),t[7]||(t[7]=i('<p>Click on <strong>Add Condition</strong> to add a new condition row. For each condition, configure:</p><ol><li><strong>Attribute:</strong> Select the attribute from the dropdown (grouped by Cart, Cart Item, and Product).</li><li><strong>Operator:</strong> Depending on the attribute type, operators include: Equals (==), Not Equals (!=), Greater Than (&gt;=), Less Than (&lt;=), Greater or Equal (&gt;=), Less or Equal (&lt;=), Contains ({}), Not Contains (!{}).</li><li><strong>Value:</strong> Enter or select the value to compare against. For category attributes, a tree selector is available.</li></ol><p>For example, if you select <strong>Categories</strong>, choose the operator <strong>contains</strong> and then select the desired category from the tree.</p><p>To delete a condition, click the <strong>Delete icon</strong> on the right side of the condition row.</p><h3 id="step-3-set-the-actions" tabindex="-1">Step 3: Set the Actions <a class="header-anchor" href="#step-3-set-the-actions" aria-label="Permalink to &quot;Step 3: Set the Actions&quot;">​</a></h3><p>In the Actions section, define how the discount will be applied. Select one of the four action types:</p>',6)),n(o,{src:"/images/marketing/cart-rule-buy-condition.png",alt:"Attribute Condition"}),t[8]||(t[8]=i("<ol><li><p><strong>Action Type:</strong> Choose how the discount is calculated.</p><p><strong>a) Percentage Product Price —</strong> Discount is applied as a percentage (%) of the product price. The discount amount is capped at 100. Apply to Shipping is available.</p><p><strong>b) Fixed Amount —</strong> A fixed discount amount is subtracted from each matching item&#39;s price. Apply to Shipping is available.</p><p><strong>c) Fixed Amount Whole Cart —</strong> The discount amount is split proportionally across all matching cart items based on their price. Apply to Shipping is disabled for this type.</p><p><strong>d) Buy X Get Y Free —</strong> Customers get free products when they buy a certain quantity. Configure &quot;Free Quantity&quot; (discount amount = number of free items) and &quot;Buy X Quantity&quot; (number of items the customer must purchase to qualify). Apply to Shipping is disabled for this type.</p></li><li><p><strong>Discount Amount / Free Quantity:</strong> Enter the discount value. For <strong>Percentage</strong> this is the percentage off. For <strong>Buy X Get Y</strong> this is the number of free items. For other types this is the fixed discount amount.</p></li><li><p><strong>Buy X Quantity:</strong> (Only for Buy X Get Y) Enter the quantity the customer must purchase to qualify for the free items.</p></li><li><p><strong>Maximum Discounted Quantity:</strong> Enter the maximum number of items that can receive the discount. (Not applicable for Fixed Amount Whole Cart.)</p></li><li><p><strong>Maximum Eligible Quantity:</strong> (Only for Buy X Get Y) Enter the maximum number of items eligible for the free discount.</p></li><li><p><strong>Apply to Shipping:</strong> Set Yes to also apply the discount to the shipping cost. Disabled for Fixed Amount Whole Cart and Buy X Get Y.</p></li><li><p><strong>Free Shipping:</strong> Set Yes to make shipping free when this rule is applied.</p></li><li><p><strong>End Other Rules:</strong> Set Yes to stop processing further cart rules after this one is applied. Useful when you have multiple overlapping discounts.</p></li></ol><p>After configuring all sections, click the <strong>Save Cart Rule</strong> button.</p><p>Now copy the <strong>Coupon Code</strong> as shown below.</p>",3)),n(o,{src:"/images/marketing/couponCode.png",alt:"Coupon Code Example"}),t[9]||(t[9]=e("h3",{id:"frontend",tabindex:"-1"},[r("Frontend "),e("a",{class:"header-anchor",href:"#frontend","aria-label":'Permalink to "Frontend"'},"​")],-1)),t[10]||(t[10]=e("p",null,[r("On the "),e("strong",null,"Checkout Page"),r(", while placing an order, click on "),e("strong",null,"Apply Coupon"),r(" as shown below.")],-1)),n(o,{src:"/images/marketing/checkoutPage.png",alt:"Checkout Page Coupon"}),t[11]||(t[11]=e("p",null,[r("After entering the coupon code, click on the "),e("strong",null,"Apply"),r(" button.")],-1)),n(o,{src:"/images/marketing/applyCoupon.png",alt:"Apply Coupon"}),t[12]||(t[12]=e("p",null,[r("Now the "),e("strong",null,"Coupon"),r(" is applied successfully.")],-1)),n(o,{src:"/images/marketing/couponApplied.png",alt:"Coupon Applied Successfully"}),t[13]||(t[13]=e("p",null,[r("By following the above steps, you can easily create "),e("strong",null,"Cart Rules"),r(" in Bagisto.")],-1))])}const b=s(p,[["render",g]]);export{C as __pageData,b as default};
